package com.camexch.browser;

final class VirtualCameraScript {
    static final String SCRIPT =
            "(function(){"
                    + "if(window.__camexchInstalled)return;window.__camexchInstalled=true;"
                    + "function log(m){try{if(window.CamExchLog)window.CamExchLog.log(String(m));}catch(e){}}"
                    + "log('Front Camera 4 hook installed url='+location.href);"
                    + "const originalGet=navigator.mediaDevices&&navigator.mediaDevices.getUserMedia?navigator.mediaDevices.getUserMedia.bind(navigator.mediaDevices):null;"
                    + "const originalEnum=navigator.mediaDevices&&navigator.mediaDevices.enumerateDevices?navigator.mediaDevices.enumerateDevices.bind(navigator.mediaDevices):null;"
                    + "const frontIds=new Set();"
                    + "let sharedRtcPromise=null;let sharedPc=null;let statsTimer=null;let probeVideo=null;let probeTrack=null;"
                    + "function constraintHas(x,value){return x===value||(x&&x.exact===value)||(x&&x.ideal===value)||(x&&Array.isArray(x.exact)&&x.exact.indexOf(value)>=0)||(x&&Array.isArray(x.ideal)&&x.ideal.indexOf(value)>=0)||(Array.isArray(x)&&x.indexOf(value)>=0);}"
                    + "function isKnownFront(x){if(typeof x==='string')return frontIds.has(x);if(!x)return false;const values=[];if(x.exact!==undefined)values.push(...(Array.isArray(x.exact)?x.exact:[x.exact]));if(x.ideal!==undefined)values.push(...(Array.isArray(x.ideal)?x.ideal:[x.ideal]));return values.some(v=>frontIds.has(v));}"
                    + "function constraintsForNative(c){if(!c||!c.video||c.video===true)return c;const v=c.video;const environment=constraintHas(v.facingMode,'environment');const synthetic=constraintHas(v.deviceId,'camexch-front-camera-4');const conflictingFront=environment&&isKnownFront(v.deviceId);if(!synthetic&&!conflictingFront)return c;const nextVideo=Object.assign({},v);delete nextVideo.deviceId;if(!environment&&!nextVideo.facingMode)nextVideo.facingMode='user';log('removed virtual deviceId before physical camera request facing='+(nextVideo.facingMode||'default'));return Object.assign({},c,{video:nextVideo});}"
                    + "function isVirtualRequest(c){"
                    + " if(!c||!c.video)return false;"
                    + " const v=c.video;"
                    + " if(v===true)return false;"
                    + " const fm=v.facingMode;"
                    + " const id=v.deviceId;"
                    + " if(constraintHas(fm,'environment'))return false;"
                    + " return constraintHas(fm,'user')||constraintHas(id,'camexch-front-camera-4')||isKnownFront(id);"
                    + "}"
                    + "async function photoStream(c){"
                    + " log('using photo stream');"
                    + " const canvas=document.createElement('canvas');"
                    + " const img=new Image();img.crossOrigin='anonymous';let alive=true;"
                    + " const photo=window.CamExchBridge&&window.CamExchBridge.getPhotoDataUrl();if(!photo||photo.indexOf('ERROR:')===0)throw new Error(photo||'Source bridge unavailable');"
                    + " await new Promise((resolve,reject)=>{img.onload=resolve;img.onerror=()=>reject(new Error('Unable to decode source photo'));img.src=photo;});canvas.width=img.naturalWidth;canvas.height=img.naturalHeight;const ctx=canvas.getContext('2d');log('photo size='+canvas.width+'x'+canvas.height);"
                    + " function draw(){try{ctx.drawImage(img,0,0,canvas.width,canvas.height);}catch(e){} if(alive)requestAnimationFrame(draw);}draw();"
                    + " const stream=canvas.captureStream(10);"
                    + " stream.getVideoTracks().forEach(t=>{const stop=t.stop.bind(t);t.stop=function(){alive=false;stop();};});"
                    + " await addAudio(stream,c);return stream;"
                    + "}"
                    + "async function addAudio(stream,c){"
                    + " if(c&&c.audio&&originalGet){try{const audio=await originalGet({audio:c.audio,video:false});audio.getAudioTracks().forEach(t=>stream.addTrack(t));}catch(e){}}"
                    + "}"
                    + "function waitIce(pc){return pc.iceGatheringState==='complete'?Promise.resolve():new Promise(resolve=>{const f=()=>{if(pc.iceGatheringState==='complete'){pc.removeEventListener('icegatheringstatechange',f);resolve();}};pc.addEventListener('icegatheringstatechange',f);setTimeout(resolve,3000);});}"
                    + "function stopProbe(){if(probeVideo){try{probeVideo.pause();probeVideo.srcObject=null;probeVideo.remove();}catch(e){}probeVideo=null;probeTrack=null;}}"
                    + "function startProbe(track){stopProbe();if(!('requestVideoFrameCallback' in HTMLVideoElement.prototype))return;const video=document.createElement('video');video.muted=true;video.playsInline=true;video.autoplay=true;video.style.cssText='position:fixed;width:1px;height:1px;opacity:0;pointer-events:none;left:-10px;top:-10px';video.srcObject=new MediaStream([track]);(document.body||document.documentElement).appendChild(video);probeVideo=video;probeTrack=track;let lastLog=0;const frame=(now,meta)=>{if(probeVideo!==video||probeTrack!==track)return;if(now-lastLog>=5000){lastLog=now;const capture=Number(meta.captureTime);const latency=Number.isFinite(capture)?Math.max(0,Math.round(now-capture)):-1;log('WebRTC frame latencyMs='+latency+' processingMs='+Math.round(1000*(meta.processingDuration||0))+' presented='+meta.presentedFrames);}video.requestVideoFrameCallback(frame);};video.play().then(()=>video.requestVideoFrameCallback(frame)).catch(e=>log('WebRTC frame probe failed '+e));}"
                    + "function stopStats(){if(statsTimer){clearInterval(statsTimer);statsTimer=null;}stopProbe();}"
                    + "function logTrackSettings(track){try{const s=track.getSettings?track.getSettings():{};log('WebRTC track settings size='+(s.width||0)+'x'+(s.height||0)+' fps='+(s.frameRate||0));}catch(e){log('WebRTC track settings failed '+e);}}"
                    + "function startStats(pc,track){stopStats();startProbe(track);const report=async()=>{try{const stats=await pc.getStats();stats.forEach(r=>{if(r.type==='inbound-rtp'&&!r.isRemote&&(r.kind==='video'||r.mediaType==='video')){const count=r.jitterBufferEmittedCount||0;const jitterMs=count?Math.round(1000*(r.jitterBufferDelay||0)/count):0;log('WebRTC inbound size='+(r.frameWidth||0)+'x'+(r.frameHeight||0)+' fps='+(r.framesPerSecond||0)+' jitterMs='+jitterMs+' decoded='+(r.framesDecoded||0)+' dropped='+(r.framesDropped||0)+' lost='+(r.packetsLost||0));}});}catch(e){log('WebRTC stats failed '+e);}};setTimeout(()=>{logTrackSettings(track);report();},250);statsTimer=setInterval(report,5000);}"
                    + "async function createRtcBase(){"
                    + " log('creating shared local RTCPeerConnection');"
                    + " const pc=new RTCPeerConnection({iceServers:[]});"
                    + " sharedPc=pc;pc.onconnectionstatechange=()=>{log('shared WebRTC state='+pc.connectionState);if((pc.connectionState==='failed'||pc.connectionState==='closed')&&sharedPc===pc){stopStats();sharedRtcPromise=null;sharedPc=null;}};"
                    + " const remote=new Promise(resolve=>{pc.ontrack=e=>resolve({track:e.track,receiver:e.receiver});});"
                    + " const transceiver=pc.addTransceiver('video',{direction:'recvonly'});try{const caps=RTCRtpReceiver.getCapabilities&&RTCRtpReceiver.getCapabilities('video');const h264=caps&&caps.codecs?caps.codecs.filter(c=>String(c.mimeType).toLowerCase()==='video/h264'):[];if(h264.length&&transceiver.setCodecPreferences){transceiver.setCodecPreferences(h264);log('WebRTC preferred codec=H264 variants='+h264.length);}}catch(e){log('WebRTC H264 preference unavailable '+e);}"
                    + " await pc.setLocalDescription(await pc.createOffer());await waitIce(pc);log('offer ready length='+pc.localDescription.sdp.length);"
                    + " const answer=window.CamExchBridge&&window.CamExchBridge.answerOffer(pc.localDescription.sdp);if(!answer||answer.indexOf('ERROR:')===0)throw new Error(answer||'Source bridge unavailable');"
                    + " log('answer received length='+answer.length);await pc.setRemoteDescription({type:'answer',sdp:answer});"
                    + " const remoteInfo=await Promise.race([remote,new Promise((resolve,reject)=>setTimeout(()=>reject(new Error('WebRTC track timeout after answer')),10000))]);const track=remoteInfo.track;const receiver=remoteInfo.receiver;try{if(receiver&&'playoutDelayHint' in receiver)receiver.playoutDelayHint=0;if(receiver&&'jitterBufferTarget' in receiver)receiver.jitterBufferTarget=0;log('WebRTC receiver low-latency hints playout='+(receiver&&receiver.playoutDelayHint)+' jitterTarget='+(receiver&&receiver.jitterBufferTarget));}catch(e){log('WebRTC receiver low-latency hints unavailable '+e);}log('remote track received state='+track.readyState+' muted='+track.muted);track.onmute=()=>log('remote track muted');track.onunmute=()=>{log('remote track unmuted');startStats(pc,track);};track.onended=()=>{log('remote track ended');stopStats();if(sharedPc===pc){sharedRtcPromise=null;sharedPc=null;}};if(!track.muted)startStats(pc,track);return {pc:pc,track:track};"
                    + "}"
                    + "async function rtcStream(c){"
                    + " if(!sharedRtcPromise)sharedRtcPromise=createRtcBase().catch(e=>{sharedRtcPromise=null;if(sharedPc){sharedPc.close();sharedPc=null;}throw e;});else log('reusing shared WebRTC track');"
                    + " const base=await sharedRtcPromise;if(base.track.readyState==='ended'){sharedRtcPromise=null;return rtcStream(c);}const track=base.track.clone();const stream=new MediaStream([track]);"
                    + " await addAudio(stream,c);return stream;"
                    + "}"
                    + "async function virtualStream(c){"
                    + " try{const mode=window.CamExchBridge&&window.CamExchBridge.getMode();if(!mode||mode.indexOf('ERROR:')===0)throw new Error(mode||'Source bridge unavailable');const activeMode=mode.trim();log('IPC bridge mode='+activeMode);if(activeMode==='Photo')return photoStream(c);if(activeMode==='RTSP'||activeMode==='Video')return await rtcStream(c);throw new Error('Source is not active: '+activeMode);}catch(e){log('Front Camera 4 unavailable, using phone camera: '+e);return originalGet(constraintsForNative(c));}"
                    + "}"
                    + "async function routeGet(c){"
                    + " log('getUserMedia '+JSON.stringify(c));"
                    + " if(isVirtualRequest(c)){log('camera route=Front Camera 4 explicit');return virtualStream(c);}"
                    + " const nativeConstraints=constraintsForNative(c);const stream=await originalGet(nativeConstraints);const v=nativeConstraints&&nativeConstraints.video;"
                    + " const track=v&&stream.getVideoTracks()[0];const facing=track&&track.getSettings?track.getSettings().facingMode:'';"
                    + " if(v&&!constraintHas(v!==true&&v.facingMode,'environment')&&facing==='user'){log('camera route=Front Camera 4 detected from native track');stream.getTracks().forEach(t=>t.stop());return virtualStream(c);}"
                    + " log('camera route=physical facing='+(facing||'unknown'));"
                    + " return stream;"
                    + "}"
                    + "if(navigator.mediaDevices&&originalGet){navigator.mediaDevices.getUserMedia=routeGet;}"
                    + "addEventListener('pagehide',()=>{stopStats();if(sharedPc){sharedPc.close();sharedPc=null;}sharedRtcPromise=null;});"
                    + "if(navigator.mediaDevices&&originalEnum){navigator.mediaDevices.enumerateDevices=async function(){"
                    + " const list=await originalEnum();"
                    + " const summary=list.map(d=>d.kind+':'+d.label).join('|');log('native devices '+summary);"
                    + " const mapped=list.map(d=>{if(d.kind!=='videoinput')return d;const label=String(d.label||'');if(/front|user|facing front/i.test(label)){frontIds.add(d.deviceId);return {deviceId:d.deviceId,kind:d.kind,label:'Front Camera 4',groupId:d.groupId,toJSON:function(){return {deviceId:this.deviceId,kind:this.kind,label:this.label,groupId:this.groupId};}};}return d;});"
                    + " if(!mapped.some(d=>d.kind==='videoinput'&&d.label==='Front Camera 4'))mapped.push({deviceId:'camexch-front-camera-4',kind:'videoinput',label:'Front Camera 4',groupId:'camexch',toJSON:function(){return {deviceId:this.deviceId,kind:this.kind,label:this.label,groupId:this.groupId};}});return mapped;"
                    + "};}"
                    + "})();";

    private VirtualCameraScript() {
    }
}
